"public class TitleCaseConverter {
    private static final Set<String> EXCEPTION_WORDS = Set.of(\"and\", \"of\", \"the\", \"is\", \"in\", \"on\", \"at\", \"by\", \"for\", \"with\", \"as\", \"an\", \"to\", \"from\", \"about\", \"over\", \"under\", \"between\", \"into\", \"through\", \"during\", \"before\", \"after\", \"out\", \"against\", \"among\", \"around\", \"below\", \"beneath\", \"beside\", \"besides\", \"between\", \"concerning\", \"considering\", \"despite\", \"except\", \"excluding\", \"following\", \"including\", \"in terms of\", \"in view of\", \"like\", \"near\", \"regarding\", \"respecting\", \"since\", \"throughout\", \"toward\", \"towards\", \"underneath\", \"versus\", \"via\", \"within\", \"without\");

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split(\"\\s+\");

        StringBuilder result = new StringBuilder();

        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            if (i == 0 || !EXCEPTION_WORDS.contains(word.toLowerCase())) {
                result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
            } else {
                result.append(word.toLowerCase());
            }
            if (i < words.length - 1) {
                result.append(\" \");
            }
        }

        return result.toString();
    }

    public static void main(String[] args) {
        String input = \"this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.\";

        String titleCase = toTitleCase(input);
        System.out.println(titleCase);
    }
}"
